private static class ProcessorToAsyncProcessorBridge 
        implements DelegateProcessor, AsyncProcessor, Navigate<Processor>, Service {

    protected final Processor processor;

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        if (processor == null) {
            callback.done(true);
            return true;
        }
        try {
            processor.process(exchange);  // Synchronous call
        } catch (Exception e) {
            exchange.setException(e);
        } finally {
            callback.done(true);  // Signal completion immediately
        }
        return true;  // Always synchronous
    }
}
