@Override
public void run() {
    try {
        // Log start
        doRun();
        // Log completion
    } catch (Error e) {
        throw e;
    } catch (Throwable e) {
        LOG.error("Error during poll, will retry");
    }
}

private void doRun() {
    if (isSuspended()) return;

    // Handle backoff logic
    if (backoffMultiplier > 0 && 
        (idleCounter >= backoffIdleThreshold || errorCounter >= backoffErrorThreshold)) {
        if (backoffCounter < backoffMultiplier) {
            return;  // Skip this poll
        }
        // Reset counters
    }

    // Check repeat count limit
    if (repeatCount > 0 && counter > repeatCount) {
        scheduler.unscheduleTask();
        return;
    }

    // Polling retry loop
    int retryCounter = -1;
    boolean done = false;
    Throwable cause = null;
    int polledMessages = 0;

    while (!done) {
        try {
            done = true;
            if (isPollAllowed()) {
                pollingCounter.incrementAndGet();
                try {
                    // Begin strategy
                    boolean begin = pollStrategy.begin(this, endpoint);
                    if (begin) {
                        retryCounter++;
                        // CALL ABSTRACT METHOD
                        polledMessages = poll();

                        // Send empty if idle
                        if (polledMessages == 0 && sendEmptyMessageWhenIdle) {
                            processEmptyMessage();
                        }

                        // Commit strategy
                        pollStrategy.commit(this, endpoint, polledMessages);

                        // Greedy: keep polling if messages
                        if (polledMessages > 0 && isGreedy()) {
                            done = false;
                            retryCounter = -1;
                            errorCounter.set(0);
                            lastError = null;
                            firstPollDone = true;
                        }
                    }
                } finally {
                    pollingCounter.decrementAndGet();
                }
            }
        } catch (Exception e) {
            // Rollback strategy - may retry
            boolean retry = pollStrategy.rollback(this, endpoint, retryCounter, e);
            if (!retry) {
                cause = e;
                done = true;
            }
        }

        // Handle exception
        if (cause != null && isRunAllowed()) {
            getExceptionHandler().handleException(
                "Failed polling endpoint", cause);
        }
    }

    // Update counters
    if (cause != null) {
        idleCounter.set(0);
        successCounter.set(0);
        errorCounter.incrementAndGet();
        lastError = cause;
    } else {
        if (polledMessages == 0) {
            idleCounter.incrementAndGet();
        } else {
            idleCounter.set(0);
        }
        successCounter.incrementAndGet();
        errorCounter.set(0);
        lastError = null;
    }

    firstPollDone = true;
}
