protected Processor createOutputsProcessor(Collection<ProcessorDefinition<?>> outputs, boolean optimize) throws Exception {
    List<Processor> list = new ArrayList<>();
    for (ProcessorDefinition<?> output : outputs) {
        // 1. Allow pre-processing
        reifier(route, output).preCreateProcessor();

        // 2. Create the processor
        Processor processor = createProcessor(output);

        // 3. Set ID and route ID
        if (processor instanceof IdAware idAware) {
            idAware.setId(getId(output));
        }
        if (processor instanceof RouteIdAware routeIdAware) {
            routeIdAware.setRouteId(route.getRouteId());
        }

        // 4. Wrap in Channel with error handlers and interceptors
        Processor channel = wrapChannel(processor, output);
        list.add(channel);
    }

    // 5. Create composite if multiple, or return single
    if (optimize && list.size() == 1) {
        return list.get(0);
    } else {
        return createCompositeProcessor(list);  // Returns Pipeline
    }
}
```

